            setText('#sys-time', `${eraName} ${eraYear} (${timeObj['Năm']||159} Năm) ${timeObj['Tháng']||1} Tháng ${timeObj['Ngày']||1} Ngày`);
            setText('#sys-title', `${base['Tiêu Đề'] || 'Không Có'} (${base['Hướng Kịch Bản'] || 'Chưa Rõ'})`);
            setText('#world-situation', base['Đại Thế Thời Đại'], 'Thiên hạ thái bình');
            setText('#sys-weather', base['Thiên Tượng'], 'Tinh Tượng Bình Chính');
            setText('#sys-nursery-rhyme', base['Đồng Dao'], 'Tạm Không Có');

            let nameStr = me['Họ Tên'] || 'Vô danh thị';
            let ziStr = me['Biểu Tự'] && me['Biểu Tự'] !== 'Không Có' ? ` Tự${me['Biểu Tự']}` : '';
            setText('#char-name', nameStr + ziStr);

            let ageStr = me['Tuổi Tác'] ? `${me['Tuổi Tác']} Tuổi` : '';
            setText('#char-info-line1', ageStr);

            let classStr = me['Giai Cấp Xuất Thân'] || 'Bình Dân';
            let titleStr = me['Quan Chức'] || 'Bạch Đinh';
            let locStr = me['Khu Vực Hiện Tại'] || 'Chưa Rõ';
            setText('#char-info-line2', `${classStr} ${titleStr} ${locStr}`);

            /* Danh Tiếng: Hiện tại là đối tượng {
                Tiêu Đề, Mô Tả
            }*/
            const repObj = me['Danh Tiếng'] || {};
            const repTitle = repObj['Tiêu Đề'] || 'Lý Lư Xưng Thiện';
            const repDesc = repObj['Mô Tả'] || '';
            let repHtml = `<span style="color:var(--highlight-purple); font-weight:bold; font-size:14px;">${repTitle}</span>`;
            if (repDesc) {
                repHtml += `<div class="rep-desc">${repDesc}</div>`;
            }
            setHtml('#char-rep-block', repHtml);

            setText('#char-eval-top', me['Đánh Giá Giai Cấp'], 'Bình Bình Vô Kỳ');

            const facDet = faction['Chi Tiết Phe Phái'] || {};
            setText('#char-fac-eval', facDet['Đánh Giá Phe Mình'], 'Tạm không có đánh giá');

            setText('#sys-crisis', base['Khủng Hoảng Hiện Tại'], 'Tạm Không Có');

            const attrs = me['Thuộc Tính'] || {};
            const attrMap = {
                'Dũng Vũ': 'dungvu',
                'Thao Lược': 'thaoluoc',
                'Nội Chính': 'noichinh',
                'Thống Ngự': 'thongngu',
                'Khí Độ': 'khido'
            };
            Object.entries(attrMap).forEach(([k, idKey]) => {
                setText(`#attr-${idKey}-val`, attrs[k] || 0);
                $(`#attr-${idKey}-bar`).css('width', `${_.clamp(attrs[k]||0, 0, 100)}%`);
            });

            setText('#attr-kien-val', attrs['Sức Khỏe'] || 0);
            $(`#attr-kien-bar`).css('width', `${_.clamp(attrs['Sức Khỏe']||0, 0, 100)}%`);

            /* Bẩm Phú */
            const traitsEntries = Object.entries(currentTraitsData);
            const traitsHtml = traitsEntries.map(([k, v]) => {
                const cleanK = k.replace(/^[\d\.\s]+/, '');
                return `<span class="policy-tag trait-tag" data-name="${k}">${cleanK}</span>`;
            }).join('');
            setHtml('#char-traits', traitsHtml || '<span style="font-size:12px;color:#5d4037;"> Tạm không có bẩm phú</span>');

            // Danh Hiệu: Bắt buộc dọn dẹp số và dấu câu ở đầu tên khóa
            const titlesEntries = Object.entries(me['Danh Hiệu'] || {});
            if (titlesEntries.length > 0) {
                const titlesHtml = titlesEntries.map(([k, v]) => {
                    const cleanK = k.replace(/^[\d\.\s]+/, '');
                    return `<div class="record-item"><div class="record-item-title">${cleanK}</div>${v ? `<div class="record-item-desc">${v}</div>` : ''}</div>`;
                }).join('');
                setHtml('#char-titles-list', titlesHtml);
            } else {
                setHtml('#char-titles-list', '<div style="font-size:12px;color:#5d4037;"> Tạm không có danh hiệu</div>');
            }

            // Công Tích: Bắt buộc dọn dẹp số và dấu câu ở đầu tên khóa
            const meritsEntries = Object.entries(me['Công Tích'] || {});
            if (meritsEntries.length > 0) {
                const meritsHtml = meritsEntries.map(([k, v]) => {
                    const cleanK = k.replace(/^[\d\.\s]+/, '');
                    return `<div class="record-item"><div class="record-item-title">${cleanK}</div>${v ? `<div class="record-item-desc">${v}</div>` : ''}</div>`;
                }).join('');
                setHtml('#char-merits-list', meritsHtml);
            } else {
                setHtml('#char-merits-list', '<div style="font-size:12px;color:#5d4037;"> Tạm không có công tích</div>');
            }

            /* Hệ Thống Kinh Tế */
            setText('#econ-gold', econ['Dự Trữ_Vàng'] || 0);
            setText('#econ-food', econ['Dự Trữ_Thạch'] || 0);
            setText('#econ-coin', econ['Dự Trữ_Tiền'] || 0);
            setText('#econ-cloth', econ['Dự Trữ_Thất'] || 0);

            const assetsHtml = Object.entries(econ['Chi Tiết Tài Sản'] || {}).map(([n, d]) =>
                `<li class="list-item"><span>${n}</span><span style="font-size:12px;"> Thu:${d['Thu Nhập']||0} Chi:${d['Chi Tiêu']||0} (${d['Loại Hình']||'Vàng'})</span></li>`
            ).join('');
            setHtml('#econ-assets', assetsHtml || '<li class="list-item" style="justify-content:center;"> Gia đồ tứ bích</li>');

            setText('#fac-name', facDet['Tên Phe Phái']);
            setText('#fac-leader', facDet['Lãnh Tụ Phe Phái']);
            setText('#fac-type', facDet['Loại Phe Phái']);
            setText('#fac-dyn', facDet['Động Thái Phe Phái']);

            const extEvalHtml = Object.entries(facDet['Đánh Giá Phe Bên Ngoài'] || {}).map(([n, d]) =>
                `<li class="list-item" style="flex-direction:column;align-items:flex-start;">
            <div style="width:100%;display:flex;justify-content:space-between;font-weight:bold;">
                <span>${n}</span>
                <span style="font-size:12px;color:var(--text-purple);">${d['Quan Hệ Ngoại Giao']||'Trung Lập'}</span>
            </div>
            <div style="width:100%;font-size:12px;color:#5d4037;margin-top:2px;font-weight:normal;">${d['Mô Tả Đánh Giá']||'Tạm Không Giao Tập'}</div>
        </li>`
            ).join('');
            setHtml('#fac-ext-evals', extEvalHtml || '<li class="list-item" style="justify-content:center;font-weight:normal;color:#5d4037;"> Tứ hải chưa yên, tạm không giao tập</li>');

            const relHtml = Object.entries(faction['Quan Hệ Nhân Tế'] || {}).map(([n, d]) =>
                `<li class="list-item"><span>${n}</span><span style="color:${d['Hảo Cảm']>=0?'var(--positive-color)':'var(--negative-color)'}; font-weight:bold;"> Hảo Cảm ${d['Hảo Cảm']>0?'+':''}${d['Hảo Cảm']||0} | ${d['Đánh Giá']||'Không Có'}</span></li>`
            ).join('');
            setHtml('#fac-relations', relHtml || '<li class="list-item" style="justify-content:center;"> Cô gia quả nhân</li>');

            const subHtml = Object.entries(currentSubData).map(([n, d]) => {
                let ageDisp = d['Tuổi Tác'] !== undefined ? `${d['Tuổi Tác']} Tuổi` : 'Tuổi tác không rõ';
                return `<li class="list-item sub-item" data-name="${n}" style="flex-direction:column;align-items:flex-start;padding:6px 0;">
            <div style="width:100%;display:flex;justify-content:space-between;font-weight:bold;">
                <span>${n} <span style="font-size:12px;font-weight:normal;color:#5d4037;">(${ageDisp})</span></span>
                <span style="font-size:12px;color:var(--text-purple);">${d['Quan Chức']||'Bạch Đinh'}</span>
            </div>
            <div style="width:100%;font-size:12px;color:#5d4037;margin-top:2px;font-weight:normal;">
                'Hảo Cảm': <span style="color:${d['Hảo Cảm']>=0?'var(--positive-color)':'var(--negative-color)'};font-weight:bold;">${d['Hảo Cảm']>0?'+':''}${d['Hảo Cảm']||0}</span> | Đánh Giá: ${d['Đánh Giá']||'Không Có'}
                <span style="float:right;color:var(--highlight-purple);"> Xem chi tiết ＞</span>
            </div>
        </li>`;
            }).join('');
            setHtml('#fac-subs', subHtml || '<li class="list-item" style="justify-content:center;"> Tạm không có bộ khúc</li>');

            const milHtml = Object.entries(currentTroopData).map(([n, d]) =>
                `<li class="list-item troop-item" data-name="${n}" style="flex-direction:column;align-items:flex-start;padding:6px 0;">
            <div style="width:100%;display:flex;justify-content:space-between;font-weight:bold;">
                <span>${n}</span>
                <span style="font-size:12px;color:var(--text-purple);">${d['Số Lượng']||0} Người</span>
            </div>
            <div style="width:100%;font-size:12px;color:#5d4037;margin-top:2px;font-weight:normal;">
                'Trú':${d['Trú Địa']||'Không Có'} Tướng:${d['Chủ Tướng']||'Không Có'}
                <br><b> Động hướng:</b> ${d['Động Thái Binh Mã']||'Đồn Trú'}
                <span style="float:right;color:var(--highlight-purple);"> Xem chi tiết ＞</span>
            </div>
        </li>`
            ).join('');
            setHtml('#mil-troops', milHtml || '<li class="list-item" style="justify-content:center;"> Dưới trướng không binh</li>');

            const famDet = family['Khái Quát'] || {};
            setText('#fam-name', famDet['Tên Gia Tộc']);
            setText('#fam-level', famDet['Cấp Bậc Gia Tộc']);
            setText('#fam-leader', famDet['Lãnh Tụ Gia Tộc']);
            setText('#fam-dyn', famDet['Động Thái Gia Tộc']);

            const kinHtml = Object.entries(family['Tử Đệ Gia Tộc'] || {}).map(([n, d]) =>
                `<li class="list-item">
            <span>${n} ${d['Biểu Tự']!=='Không Có'?`(${d['Biểu Tự']})`:''}</span>
            <span style="font-size:12px;color:#5d4037;">${d['Quan Hệ']||'Chưa Rõ'} | ${d['Tuổi Tác']||0} Tuổi | ${d['Quan Chức']||'Bạch Đinh'} | ${d['Đánh Giá']||'Không Có'}</span>
         </li>`
            ).join('');
            setHtml('#fam-kin', kinHtml || '<li class="list-item" style="justify-content:center;"> Nhân đinh đơn bạc</li>');

            setText('#har-rumor', me['Tin Đồn Mỹ Nhân Thiên Hạ'], 'Tạm không có tin đồn');
            setText('#har-dyn', harem['Động Hướng Hậu Cung']);
            setText('#har-kid-dyn', harem['Động Hướng Tử Tự']);

            const wifeHtml = Object.entries(currentHaremData).map(([n, d]) => {
                let sexTotal = d['Số Lần Ân Ái'] || 0;
                let titleDisp = d['Vị Phân'] && d['Vị Phân'] !== 'Không Có' ? `[${d['Vị Phân']}] ` : '';
                return `<li class="list-item wife-item" data-name="${n}">
            <span>${titleDisp}${n} (${d['Tuổi Tác']||16} Tuổi)</span>
            <span style="font-size:12px; font-weight:normal; color:#5d4037;">
              Hảo Cảm: ${d['Hảo Cảm']||0} | Sủng Ái: ${d['Sủng Ái']||0} | Thừa hoan: ${sexTotal} lần
            </span>
          </li>`;
            }).join('');
            setHtml('#har-wives', wifeHtml || '<li class="list-item" style="justify-content:center;"> Hậu viện trống rỗng</li>');

            const kidHtml = Object.entries(harem['Tử Tự'] || {}).map(([n, d]) =>
                `<li class="list-item" style="flex-direction:column; align-items:flex-start; padding: 4px 0;">
                    <span style="font-weight:bold;">${n} (${d['Tuổi Tác']||0} Tuổi)</span>
                    <span style="font-size:12px; font-weight:normal; color:#5d4037; margin-top:4px;">
                        Mẹ Đẻ: <b style="color:var(--highlight-purple);">${d['Mẹ Đẻ'] || 'Chưa Rõ'}</b> | 
                        Hảo Cảm: <span style="color:${d['Hảo Cảm']>=0?'var(--positive-color)':'var(--negative-color)'};font-weight:bold;">${d['Hảo Cảm']>0?'+':''}${d['Hảo Cảm']||0}</span> | 
                        Chức Vụ: ${d['Chức Vụ']||'Không Có'} | Đánh Giá: ${d['Đánh Giá']||'Không Có'}
                    </span>
                </li>`
            ).join('');
            setHtml('#har-kids', kidHtml || '<li class="list-item" style="justify-content:center;"> Dưới gối không con</li>');
        }

        async function init() {
            await waitGlobalInitialized('Mvu');
            populateCharacterData();
            eventOn(Mvu.events.VARIABLE_UPDATE_ENDED, populateCharacterData);

            $('.section-header').off('click').on('click', function() {
                $(this).toggleClass('collapsed').next('.section-content').toggleClass('hidden');
            });

            /* Cửa sổ bật lên khi nhấp vào nhãn bẩm phú */
            $(document).off('click', '.trait-tag').on('click', '.trait-tag', function() {
                const name = $(this).data('name');
                const d = currentTraitsData[name];
                if (!d) return;

                const cleanName = name.replace(/^[\d\.\s]+/, '');

                $('#modal-trait-title').text(`Bẩm Phú - ${cleanName}`);

                let traitHtml = '';
                if (typeof d === 'object') {
                    traitHtml = `<div class="trait-modal-item">
                <div class="trait-modal-name">${cleanName}</div>
                ${d['Gia Thành'] ? `<div class="trait-modal-bonus"> Gia Thành:${d['Gia Thành']}</div>` : ''}
                ${d['Mô Tả'] ? `<div class="trait-modal-desc">${d['Mô Tả']}</div>` : ''}
            </div>`;
                } else {
                    traitHtml = `<div class="trait-modal-item">
                <div class="trait-modal-name">${cleanName}</div>
                <div class="trait-modal-bonus"> Gia Thành:${d}</div>
            </div>`;
                }

                $('#modal-trait-desc').html(traitHtml);
                $('#trait-modal').css('display', 'flex');
            });

            $('#har-wives').off('click', '.wife-item').on('click', '.wife-item', function() {
                currentWifeName = $(this).data('name');
                const d = currentHaremData[currentWifeName];
                if (!d) return;

                $('#modal-wife-title').text(`${currentWifeName} Hồ sơ bí mật của`);

                if (portraits[currentWifeName]) {
                    $('.portrait-container').show();
                    const fav = d['Hảo Cảm'] || 0;
                    const pData = portraits[currentWifeName];

                    if (fav >= 61) {
                        availableImages = [...(pData.normal || []), ...(pData.nsfw || [])];
                    } else {
                        availableImages = [...(pData.normal || [])];
                    }

                    if (typeof wifeImageIndexes[currentWifeName] === 'undefined') {
                        wifeImageIndexes[currentWifeName] = 0;
                    }
                    if (wifeImageIndexes[currentWifeName] >= availableImages.length) {
                        wifeImageIndexes[currentWifeName] = 0;
                    }

                    currentImageIndex = wifeImageIndexes[currentWifeName];

                    if (availableImages.length > 0) {
                        $('#modal-wife-img').attr('src', availableImages[currentImageIndex]);

                        if (availableImages.length > 1) {
                            $('#modal-wife-img').css('cursor', 'pointer');
                            if (fav >= 61) {
                                $('#portrait-hint').text('Nhấp để chuyển đổi toàn bộ hình ảnh bí mật');
                            } else {
                                $('#portrait-hint').text(`Hảo cảm không đủ(${fav}/61),Chỉ hiển thị thường ngày(Nhấp để chuyển đổi)`);
                            }
                        } else {
                            $('#modal-wife-img').css('cursor', 'default');
                            if (fav >= 61) {
                                $('#portrait-hint').text('Tạm không có thêm hình ảnh');
                            } else {
                                $('#portrait-hint').text(`Độ hảo cảm không đủ (${fav}/61)`);
                            }
                        }
                    }
                } else {
                    $('.portrait-container').hide();
                    availableImages = [];
                }

                let tagsHtml = '';
                if (d['Nhãn']) {
                    tagsHtml += '<div class="wife-tag-container">';
                    const tagNames = ['Lần Đầu', 'Sơ Hôn', 'Sơ Luyến'];
                    tagNames.forEach(t => {
                        if (d['Nhãn'][t]) {
                            const keep = d['Nhãn'][t]['Giữ Nguyên'];
                            const target = d['Nhãn'][t]['Đối Tượng'];
                            if (keep) {
                                tagsHtml += `<span class="wife-tag active">${t}</span>`;
                            } else {
                                tagsHtml += `<span class="wife-tag inactive">${t}<span class="wife-tag-target"> Với ${target !== 'Không Có' ? target : 'Người khác'}</span></span>`;
                            }
                        }
                    });
                    tagsHtml += '</div>';
                }

                $('#modal-wife-desc').html(`
          ${tagsHtml}
          <b> Vị Phân:</b>${d['Vị Phân']||'Không Có'}<br>
          <b> Dung mạo:</b>${d['Ngoại Hình']||'Không Có'}<br>
          <b> Đánh Giá:</b>${d['Đánh Giá']||'Không Có'}<br>
          <hr style="border:0; border-top:1px dashed #d7ccc8; margin:8px 0;">
          <b> Số lần thừa hoan:</b>${d['Số Lần Ân Ái']||0} Lần
        `);

                $('#wife-modal').css('display', 'flex');
            });

            $('#modal-wife-img').off('click').on('click', function() {
                if (availableImages.length > 1) {
                    currentImageIndex = (currentImageIndex + 1) % availableImages.length;
                    $(this).attr('src', availableImages[currentImageIndex]);
                    wifeImageIndexes[currentWifeName] = currentImageIndex;
                }
            });

            $('#fac-subs').off('click', '.sub-item').on('click', '.sub-item', function() {
                const name = $(this).data('name');
                const d = currentSubData[name];
                if (!d) return;

                $('#modal-sub-title').text(`Hồ sơ bộ tướng - ${name}`);
                const attrs = d['Thuộc Tính'] || {};

                $('#modal-sub-desc').html(`
          <div class="attr-row"><span> Dũng Vũ:</span><span class="val">${attrs['Dũng Vũ']||0}</span></div>
          <div class="attr-row"><span> Thao Lược:</span><span class="val">${attrs['Thao Lược']||0}</span></div>
          <div class="attr-row"><span> Nội Chính:</span><span class="val">${attrs['Nội Chính']||0}</span></div>
          <div class="attr-row"><span> Thống Ngự:</span><span class="val">${attrs['Thống Ngự']||0}</span></div>
          <div class="attr-row"><span> Khí Độ:</span><span class="val">${attrs['Khí Độ']||0}</span></div>
          <div class="attr-row"><span> Sức Khỏe:</span><span class="val" style="color:var(--main-purple);">${attrs['Sức Khỏe']||0}</span></div>
        `);
                $('#sub-modal').css('display', 'flex');
            });

            $('#mil-troops').off('click', '.troop-item').on('click', '.troop-item', function() {
                const name = $(this).data('name');
                const d = currentTroopData[name];
                if (!d) return;

                $('#modal-troop-title').text(`Mật báo quân tình - ${name}`);

                $('#modal-troop-desc').html(`
          <div class="attr-row"><span> Tình Trạng Trung Thành:</span><span class="val">${d['Tình Trạng Trung Thành']||'Không Có'}</span></div>
          <div class="attr-row"><span> Trạng Thái Tiếp Tế:</span><span class="val">${d['Trạng Thái Tiếp Tế']||'Không Có'}</span></div>
          <div class="attr-row"><span> Tình trạng sĩ khí:</span><span class="val">${d['Sĩ Khí']||'Không Có'}</span></div>
          <div class="attr-row"><span> Mức độ huấn luyện:</span><span class="val">${d['Huấn Luyện']||'Không Có'}</span></div>
          <div class="attr-row"><span> Tình trạng trang bị:</span><span class="val">${d['Trang Bị']||'Không Có'}</span></div>
          <hr style="border:0; border-top:1px dashed #d7ccc8; margin:8px 0;">
          <div style="font-weight:normal;color:#5d4037;line-height:1.5;">
            <b> Giải thích đặc biệt:</b><br>
            ${d['Giải Thích']||'Tạm không có giải thích'}
          </div>
        `);
                $('#troop-modal').css('display', 'flex');
            });

            $('.modal-close').on('click', function() {
                $(this).closest('.modal-overlay').css('display', 'none');
            });
            $('.modal-overlay').on('click', function(e) {
                if (e.target === this) {
                    $(this).css('display', 'none');
                }
            });
        }

        $(errorCatched(init));
    </script>
</head>

